277	// ── Public entry point ────────────────────────────────────────────────────────
278	
279	export async function contractsFetcher(
280	  trade: string
281	): Promise<{ leads: RawLead[]; stats: Record<string, SourceStats> }> {
282	  const [cfSettled, ftsSettled] = await Promise.allSettled([
283	    fetchContractsFinder(trade),
284	    fetchFTS(trade),
285	  ]);
286	
287	  const cf = cfSettled.status === 'fulfilled'
288	    ? cfSettled.value
289	    : { leads: [], stats: { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'ContractsFinder threw unexpectedly' } };
290	
291	  const fts = ftsSettled.status === 'fulfilled'
292	    ? ftsSettled.value
293	    : { leads: [], stats: { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'FTS threw unexpectedly' } };
294	
295	  // Log endpoint + status to stderr (visible in server logs, not surfaced to user)
296	  console.error(`[CF]  ${CF_OCDS_BASE} → fetched=${cf.stats.fetched} passed=${cf.stats.passed} failed=${cf.stats.failed}${cf.stats.error ? ' ERR=' + cf.stats.error : ''}`);
297	  console.error(`[FTS] ${FTS_BASE} → fetched=${fts.stats.fetched} passed=${fts.stats.passed} failed=${fts.stats.failed}${fts.stats.error ? ' ERR=' + fts.stats.error : ''}`);
298	
299	  return {
300	    leads: [...cf.leads, ...fts.leads],
301	    stats: { ContractsFinder: cf.stats, FTS: fts.stats },
302	  };
303	}
