@import url('https://fonts.googleapis.com/css2?family=Barlow:wght@400;500;600;700;800&family=Barlow+Condensed:wght@600;700;800&display=swap');
@import "tailwindcss";

@theme {
  --font-sans: "Barlow", ui-sans-serif, system-ui, sans-serif;
  --font-display: "Barlow Condensed", ui-sans-serif, system-ui, sans-serif;
}

@layer base {
  * {
    box-sizing: border-box;
  }

  html {
    scroll-behavior: smooth;
    scroll-padding-top: 7rem;
  }

  body {
    margin: 0;
    min-width: 320px;
    background:
      radial-gradient(circle at top, rgba(245, 208, 0, 0.12), transparent 28%),
      linear-gradient(180deg, #090f1b 0%, #101826 100%);
    color: #e7e5e4;
    font-family: var(--font-sans);
  }

  a {
    color: inherit;
    text-decoration: none;
  }

  button,
  input,
  select,
  textarea {
    font: inherit;
  }

  #root {
    min-height: 100vh;
  }
}

@layer components {
  .site-shell {
    @apply mx-auto w-full max-w-6xl px-4 sm:px-6;
  }

  .section-gap {
    @apply py-16 sm:py-20;
  }

  .nav-shell {
    @apply flex items-center justify-between gap-4 rounded-3xl border border-white/12 bg-slate-950/85 px-4 py-4 shadow-[0_18px_60px_rgba(0,0,0,0.28)] backdrop-blur sm:px-6;
  }

  .brand-lockup {
    @apply flex items-center gap-3;
  }

  .brand-badge {
    @apply inline-flex h-12 w-12 items-center justify-center rounded-full border border-amber-300/45 bg-amber-300/10 font-display text-2xl font-bold uppercase tracking-[0.08em] text-amber-300;
  }

  .brand-wordmark {
    @apply font-display text-3xl leading-none tracking-[0.06em] text-white;
  }

  .brand-subline {
    @apply mt-1 text-[0.65rem] font-bold uppercase tracking-[0.28em] text-slate-400;
  }

  .nav-link {
    @apply text-xs font-bold uppercase tracking-[0.26em] text-slate-300 transition hover:text-white;
  }

  .cta-chip {
    @apply inline-flex items-center justify-center rounded-full bg-amber-300 px-5 py-3 text-xs font-extrabold uppercase tracking-[0.24em] text-slate-950 transition hover:bg-amber-200;
  }

  .mobile-toggle {
    @apply inline-flex h-11 w-11 flex-col items-center justify-center gap-1 rounded-full border border-white/12 bg-white/5;
  }

  .mobile-toggle span {
    @apply block h-0.5 w-5 rounded-full bg-white;
  }

  .mobile-nav {
    @apply mt-3 rounded-3xl border border-white/12 bg-slate-950/92 px-4 py-3 shadow-[0_18px_60px_rgba(0,0,0,0.28)] backdrop-blur;
  }

  .mobile-nav-link {
    @apply block border-b border-white/10 py-4 text-xs font-bold uppercase tracking-[0.26em] text-slate-200;
  }

  .hero-panel {
    @apply grid gap-6 rounded-[2rem] border border-white/12 bg-slate-950/85 px-6 py-8 shadow-[0_22px_80px_rgba(0,0,0,0.3)] sm:px-8 sm:py-10 lg:grid-cols-[1.08fr_0.92fr];
  }

  .hero-copy {
    @apply flex flex-col justify-center;
  }

  .hero-title {
    @apply mt-4 font-display text-5xl uppercase leading-[0.9] tracking-[0.04em] text-white sm:text-6xl lg:text-7xl;
  }

  .hero-body {
    @apply mt-5 max-w-2xl text-lg font-semibold leading-8 text-slate-300;
  }

  .hero-actions {
    @apply mt-8 flex flex-col gap-3 sm:flex-row;
  }

  .hero-points {
    @apply mt-8 flex flex-wrap gap-3 p-0;
    list-style: none;
  }

  .hero-points li {
    @apply rounded-full border border-white/12 bg-white/5 px-4 py-2 text-xs font-bold uppercase tracking-[0.22em] text-slate-200;
  }

  .section-kicker {
    @apply inline-flex items-center gap-2 text-xs font-bold uppercase tracking-[0.32em] text-amber-300;
  }

  .section-head {
    @apply mb-8 flex flex-col gap-3;
  }

  .section-title {
    @apply font-display text-4xl uppercase leading-none tracking-[0.04em] text-white sm:text-5xl;
  }

  .section-body {
    @apply max-w-3xl text-base font-semibold leading-8 text-slate-300;
  }

  .signal-card {
    @apply rounded-[1.75rem] border border-amber-300/22 bg-[#0b1220] p-5 shadow-[0_18px_60px_rgba(0,0,0,0.2)];
  }

  .signal-label {
    @apply text-xs font-bold uppercase tracking-[0.3em] text-amber-300;
  }

  .signal-stack {
    @apply mt-2 text-[0.7rem] font-bold uppercase tracking-[0.2em] text-slate-500;
  }

  .signal-item {
    @apply mt-4 flex gap-4 rounded-2xl border border-white/8 bg-white/5 p-4;
  }

  .signal-item-muted {
    @apply bg-black/20;
  }

  .signal-tag {
    @apply inline-flex h-fit rounded-full bg-amber-300 px-3 py-1 text-[0.65rem] font-extrabold uppercase tracking-[0.22em] text-slate-950;
  }

  .signal-tag-muted {
    @apply bg-slate-700 text-slate-200;
  }

  .signal-title {
    @apply font-display text-2xl uppercase leading-none text-white;
  }

  .signal-meta {
    @apply mt-2 text-xs font-semibold uppercase tracking-[0.22em] text-slate-400;
  }

  .metric-row {
    @apply mt-4 grid gap-3 sm:grid-cols-3;
  }

  .metric-card {
    @apply rounded-2xl border border-white/8 bg-white/5 px-4 py-4 text-center;
  }

  .metric-value {
    @apply font-display text-3xl uppercase text-white;
  }

  .metric-label {
    @apply mt-1 text-[0.65rem] font-bold uppercase tracking-[0.22em] text-slate-500;
  }

  .trust-grid,
  .feature-grid,
  .pricing-grid {
    @apply grid gap-4 lg:grid-cols-3;
  }

  .trust-card,
  .feature-card,
  .pricing-card,
  .advantage-card,
  .step-card,
  .cta-panel {
    @apply rounded-[1.75rem] border border-white/10 bg-white/5 p-6 shadow-[0_18px_60px_rgba(0,0,0,0.18)];
  }

  .trust-value,
  .feature-eyebrow,
  .pricing-name,
  .advantage-headline {
    @apply text-xs font-bold uppercase tracking-[0.28em] text-amber-300;
  }

  .trust-copy,
  .feature-copy,
  .step-copy,
  .pricing-note,
  .advantage-list,
  .cta-panel .section-body {
    @apply mt-4 text-base font-semibold leading-8 text-slate-300;
  }

  .steps-grid {
    @apply grid gap-4 md:grid-cols-3;
  }

  .step-number {
    @apply text-sm font-bold uppercase tracking-[0.28em] text-slate-500;
  }

  .step-title,
  .feature-title {
    @apply mt-4 font-display text-3xl uppercase leading-none text-white;
  }

  .advantage-grid {
    @apply grid gap-4 lg:grid-cols-2;
  }

  .advantage-card-strong {
    @apply border-amber-300/28 bg-[#131d31];
  }

  .advantage-list {
    @apply mb-0 ml-5;
  }

  .advantage-list-muted {
    @apply text-slate-400;
  }

  .pricing-card {
    @apply flex h-full flex-col;
  }

  .pricing-card-accent {
    @apply border-amber-300/28 bg-[#131d31];
  }

  .pricing-price {
    @apply mt-4 font-display text-5xl uppercase text-white;
  }

  .pricing-points {
    @apply mt-5 flex-1 space-y-3 p-0 text-sm font-semibold uppercase tracking-[0.16em] text-slate-200;
    list-style: none;
  }

  .primary-button {
    @apply inline-flex items-center justify-center rounded-full bg-amber-300 px-6 py-3 text-sm font-extrabold uppercase tracking-[0.24em] text-slate-950 transition hover:bg-amber-200;
  }

  .secondary-button {
    @apply inline-flex items-center justify-center rounded-full border border-white/15 px-6 py-3 text-sm font-extrabold uppercase tracking-[0.24em] text-white transition hover:border-white/30 hover:bg-white/5;
  }

  .cta-panel {
    @apply text-center;
  }
}

@media (max-width: 767px) {
  html {
    scroll-padding-top: 8.5rem;
  }

  .primary-button,
  .secondary-button,
  .cta-chip {
    @apply w-full;
  }
}

